from sys import stdin

class Solution:

def insert(self, root, word):
	for i in range(len(word)):
		if root.left is None:
			root.left = TrieNode(word[i])
		root = root.left
		else:
			root = root.left

	for i in range(len(word)):
		if root.right is None:
			root.right = TrieNode(word[i])
		root = root.right
		else:
			root = root.right


def deleteWord(self, root, word):
	def _deleteWord(root, word, index):
		if index == len(word):
			if root.left is None:
				return
			root.left = None
			return

		else:
			if root.left is not None and root.left.c == word[index]:
				_deleteWord(root.left, word, index + 1)
			elif root.right is not None and root.right.c == word[index]:
				_deleteWord(root.right, word, index + 1)
			else:
				root.left = None
				root.right = None
			return

			_deleteWord(root, word, index + 1)

	def deleteWordHelper(root, word):
		root.left, root.right = _deleteWord(root.left, word, 0), _deleteWord(root.right, word, 0)
		return root

	return deleteWordHelper(root, word)


def countWords(self, root):
	def _countWords(root):
		if root is None:
			return 0

		else:
			return 1 + _countWords(root.left) + _countWords(root.right)

	return _countWords(root)

