// C++ solution file
#include <iostream>
#include <sstream>
#include <string>
#include <vector>

using namespace std;

const int BUFFER_SIZE = 1024;

class Solution {
public:
void insert(TrieNode* root, const string& word);
void deleteWord(TrieNode* root, const string& word);
void autoComplete(TrieNode* root, const string& word, int index);

int countWords(TrieNode* root);
};

struct TrieNode {
char c;
TrieNode* left;
TrieNode* right;
};

void Solution::insert(TrieNode* root, const string& word) {
for (int i = 0; i < word.length(); ++i) {
if (root->left == nullptr) {
root->left = new TrieNode();
root->left->c = word[i];
}
root = root->left;
}
for (int i = 0; i < word.length(); ++i) {
if (root->right == nullptr) {
root->right = new TrieNode();
root->right->c = word[i];
}
root = root->right;
}
}

void Solution::deleteWord(TrieNode* root, const string& word) {
define _deleteWord(TrieNode* root, const string& word, int index) {
if (index == word.length()) {
if (root->left == nullptr) {
return;
}
root->left = nullptr;
return;
}

else {
if (root->left != nullptr && root->left->c == word[index]) {
_deleteWord(root->left, word, index + 1);
}
else if (root->right != nullptr && root->right->c == word[index]) {
_deleteWord(root->right, word, index + 1);
}
else {
root->left = nullptr;
root->right = nullptr;
return;
}
}
}

define deleteWordHelper(TrieNode* root, const string& word) {
root->left = _deleteWord(root->left, word, 0);
root->right = _deleteWord(root->right, word, 0);
return root;
}

return deleteWordHelper(root, word);
}

int Solution::countWords(TrieNode* root) {
define _countWords(TrieNode* root) {
if (root == nullptr) {
return 0;
}

else {
return 1 + _countWords(root->left) + _countWords(root->right);
}
}

return _countWords(root);
}

int main() {
TrieNode* root = nullptr;
int num_operations;
scanf("%d", &num_operations);
for (int i = 0; i < num_operations; ++i) {
char operation[BUFFER_SIZE];
scanf("%s", operation);
if (strcmp(operation, "INSERT") == 0) {
char word[BUFFER_SIZE];
scanf("%s", word);
root = Solution().insert(root, word);
}
else if (strcmp(operation, "DELETE") == 0) {
char word[BUFFER_SIZE];
scanf("%s", word);
root = Solution().deleteWord(root, word);
}
}

printf("%d", Solution().countWords(root));
return 0;
}
